<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('GlobalTask') }} </h4>
                        <button type="button" class="close" v-on:click="CloseGlobalTaskList">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form :buttons="buttons" :schema="FormSchema" ref="AcceptRejectForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>   
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../../services/DataService';
export default{
    props:{
        GlobalTask:{
            type:Object,
            Required:true
        }
    },
    data(){
        return{
            isLoading:false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [
                {
                    layoutType: "four",
                    Data: [
                            {
                                astype: "TextField",                 
                                label: this.$t('TaskName'),
                                name: "TaskName",
                                value: "", 
                                placeholder: this.$t('Enter Task Name'), 
                                validationRules: { "required": true, max: 4000 }
                            },
                            {
                                astype: "NumericField",                 
                                label: this.$t('TaskRate'),
                                name: "TaskRate",
                                value: "", 
                                placeholder: this.$t('Enter Task Rate'), 
                                validationRules: { "required": true, max: 4000 }
                            },
                            {
                                astype: "toggleField",
                                label: this.$t('Isbillable'),
                                name: "Isbillableglobal",
                                value: "",
                                placeholder: this.$t('EnterDescription'),
                                validationRules: "",
                            },
                            {
                            astype: "SelectField",                                                
                            label: this.$t('Status'),
                            name: "StatusId",
                            value: "",  
                            config: {
                                options: []
                            },                           
                            placeholder: this.$t('Select Issue Type'),
                            validationRules: { "required": true, max: 100 },
                        },                      
                        ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": true, max: 4000 },
                            config: {
                                rows:5
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save"
                },            
                {
                    type: "submit",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseGlobalTaskList,
                },
            ],
            percentage_completed:0,
            estimated_hours:0,
            task_id:0,
             Currency:''
        }
    },
    created:function(){
        var ths = this;
        ths.Currency=ths.GetUserInfo.Currency.replace(/[()]/g, '');
        ths.FormSchema[0].Data[1].label=ths.$t('TaskRate')+"("+ths.Currency+")";
        ths.StatusDropdown();
        if(ths.GlobalTask != null){
            ths.BindGlobalTask();
        }
    },
    methods:{
        BindGlobalTask(){
            var ths=this;
            ths.task_id=ths.GlobalTask.TASK_ID;
            ths.FormSchema[0].Data[0].value=ths.GlobalTask.TASK_NAME;
            ths.FormSchema[0].Data[1].value=ths.GlobalTask.TASK_RATE;
            ths.FormSchema[0].Data[2].value=ths.GlobalTask.IS_BILLABLE;
            ths.FormSchema[0].Data[3].value=ths.GlobalTask.STATUS_ID;
            ths.FormSchema[1].Data[0].value=ths.GlobalTask.TASK_DESC;

        },
        StatusDropdown:function(){            
            var vm= this;
            var url=`langCode=en&companyId=&statusType=Category&hasGlobal=true`
            DataService.StatusListing(url).then((response)=>{                
                if (response.data != null && response.data != "") {
                    var StatusList = response.data.result.data; 
                    StatusList.forEach(element => {
                        let Obj={
                            name:element.STATUS,
                            value:element.STATUS_ID
                        }
                        vm.FormSchema[0].Data[3].config.options.push(Obj);
                        vm.$refs.AcceptRejectForm.UpdateKeyValue();   
                    });                 
                }
            });
        },
        onSubmit(){                        
            var ths =this;
            ths.isLoading=true;
            var Obj={
                task_id:ths.task_id,
                task_name : ths.FormSchema[0].Data[0].value,
                task_rate : parseFloat(ths.FormSchema[0].Data[1].value).toFixed(2),
                task_description : ths.FormSchema[1].Data[0].value,
                is_billable : ths.FormSchema[0].Data[2].value,
                parent_task_id : 0,
                status_id : ths.FormSchema[0].Data[3].value,
                is_global : true,
                estimated_hours:parseFloat(ths.estimated_hours).toFixed(2),
                percentage_completed:parseFloat(ths.percentage_completed).toFixed(2)
            }  
            var objectPostString = JSON.stringify(Obj);
            DataService.SaveGlobalTask(objectPostString).then(function (response) { 
                ths.isLoading=false;
                if(response.data.result.DATA.length>0){ 
                    if(response.data.result.DATA[0].VALUE=='EXISTS') {
                        ths.ShowAlert(ths.$t('AlreadyExists',[ths.$t('Task')]),"warning", true, ths.$t("Alert"));
                    }
                    else if(response.data.result.DATA[0].VALUE=='UPDATE'){
                        ths.ShowAlert(ths.$t('UpdatedSuccess',[ths.$t('GlobalTask')]), "success", true,  ths.$t("Alert"));
                    }
                    else{
                        ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('GlobalTask')]), "success", true,  ths.$t("Alert"));
                    } 
                    ths.$parent.FetchData();    
                    ths.CloseGlobalTaskList();                
                }else{
                    ths.ShowAlert(ths.$t("UnknownErrorOccur"), "failure", true, ths.$t('Alert'));
                }
                
            }); 

        },
        CloseGlobalTaskList:function(){
            this.$parent.IsAddCloseGlobalTask=false;
        }
    }
}
</script>