<template>
  <section>
    <loader :is-visible="isLoading"></loader>
    <tg-list ref="tgList" :listType="['List']" :IsShowAction="false" :showCheckBox="true" ModuleName="PROJECT"
      SubModuleCode="Task" IdentityColumn="TASK_ID" :HeaderText="$t('ManageGlobalTasks')" :ListData="GlobalTaskData"
      :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords"
      :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData"
      :SortExp="SortExp" :SortBy="SortBy" :LegendArray="LegendArray" :NorecordfoundText="$t('NoRecordfound')"
      v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
      v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick" :routeInfo="$router"
      v-on:SortdataButtonClick="sortdata" :Key="Key">
      <template v-slot:slotdata="{ data }">
        <template v-if="data.column.COLUMN_NAME == 'IS_BILLABLE'">
          <span v-if="data.row.IS_BILLABLE">{{ $t('Yes') }}</span>
          <span v-else>{{ $t('No') }}</span>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'TASK_RATE'">
          <span>  {{$n(data.row.TASK_RATE,'currency',$getLocaleByCurrency(Currency)) }}</span>
         
        </template>
        <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
          
          <listing-status :isfor="'PROJECTGLOBALTASKSTATUS'" ref="updatestatus" v-bind:dataid="data.row.TASK_ID"
            data-controller="GlobalTask" v-bind:statuslist="StatusList" v-bind:item="data"
            v-bind:parentid="data.row.PARENT_TASK_ID" data-action="index" v-bind:dataselected="data.row.status_name"
            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
          </listing-status>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'TASKNAME'">
          <a href="javascript:;" @click="AddGlobalTask(data.row)">{{ data.row.TaskNumber }} {{ data.row.TASKNAME }}</a>
        </template>
      </template>
    </tg-list>
    <AddGlobalTask v-if="IsAddCloseGlobalTask" :GlobalTask="GlobalTask"></AddGlobalTask>
  </section>
</template>
<script>
import Schema from './GlobalTaskSchema'
import AddGlobalTask from './Add.vue';
import DataService from '../../../services/DataService';
export default {
  components: {
    AddGlobalTask
  },
  data() {
    return {
      Key:0,
      isLoading: false,
      GlobalTaskData: [],
      widgets: [],
      StatusList: [],
      Headers: [
        {
          "COLUMN_NAME": "TASKNAME",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Task Name",
          "DISPLAY_ORDER": 1,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "IS_BILLABLE",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Is Billable",
          "DISPLAY_ORDER": 2,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "TASK_RATE",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Task Rate",
          "DISPLAY_ORDER": 3,
           settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "STATUS_ID",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Status",
          "DISPLAY_ORDER": 4,
          settings: {
            isInSlot: true
          }
        },
      ],
      searchCondition: '',
      LegendArray: [],
      SortExp: '',
      SortBy: '',
      TotalRecords: 0,
      PageNumber: 1,
      PageSize: 10,
      CurrentPage: 1,
      listheaderbuttons: Schema.buttons,
      leftSearchFields: Schema.leftsearchSchema,
      listActions: Schema.listActions,
      IsAddCloseGlobalTask: false,
      GlobalTask: null,
      statusValues:null,
      Currency:''
    }
  },
  created: function () {
    var ths = this;
    Schema.bindleftCommonSearchdropdown(ths, "GlobalTask", "Status");
    ths.StatusDropdown();
    ths.FetchData();
    ths.Currency=ths.GetUserInfo.Currency.replace(/[()]/g, '');
    ths.Headers.forEach((element)=>{
       if( element.COLUMN_NAME=='TASK_RATE')
       {
           element.DISPLAY_NAME=  element.DISPLAY_NAME +' (' +ths.Currency +')'
       }
      })
  },
  methods: {
    StatusDropdown: function () {
      var vm = this;
      var url = `langCode=en&companyId=&statusType=Category&hasGlobal=true`
      DataService.StatusListing(url).then((response) => {
        if (response.data != null && response.data != "") {
          vm.StatusList = response.data.result.data;
        }
      });
    },
    Convertdecimal(itm) {
      debugger
      var acvc = itm.toFixed(2);
      return itm.toFixed(2);
    },
    renderActions: function (row) {
      var self = this;
      let rtnActionArray = [];
    },
    pagerMethod: function (value) {
      this.PageSize = value.PageSize;
      this.PageNumber = value.PageNumber;
      this.FetchData();
    },
    leftCommonSearch: function (value) {
      
      var vm =this;
      if (typeof value.searchConditionJson !== 'undefined') {
        if (value.searchConditionJson !== '') {
            
            if (value.searchConditionJson && value.searchConditionJson.includes("status=")) {
                vm.statusValues = value.searchConditionJson.split("status=")[1];                 
            }
            if (value.searchConditionJson && value.searchConditionJson.includes("task_name=")) {
                vm.searchCondition = value.searchConditionJson.split("task_name=")[1];                 
            }

        }
        else {
          this.searchCondition = "";
        }
      }
      else {
        this.searchCondition = "";
      }
      this.FetchData();
    },


    sortdata: function (s) {
      var SortDir = "sort tb_headerSortDown";
      this.SortBy = s;
      if (s === this.SortBy) {
        if (this.SortExp == "") {
          this.SortExp = "ASC";
          SortDir = "sort tb_headerSortDown";
        }
        else if (this.SortExp == "ASC") {
          this.SortExp = "DESC";
          SortDir = "sort tb_headerSortUp";
        }
        else {
          this.SortExp = "ASC";
          SortDir = "sort tb_headerSortDown";
        }
      }
      this.FetchData();
      $("#" + s + '  span:first-child').attr("class", SortDir);
    },
    actionButtonClick: function (callbackfunction, item) { },
    commonHeaderButtonClick: function (event) {
      switch (event.callbackfunction) {
        case "AddGlobalTask":
          this.AddGlobalTask(null);
          break;
        case "commonDeleteData":
          this.commonDeleteData();
          break;
      }
    },
    FetchData: function () {
      
      var ths = this;
      if(ths.statusValues != null){
        var url = `statusIds=${ths.statusValues}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&projectId=&search=${ths.searchCondition}`;
      }else{
        var url = `statusIds=&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&projectId=&search=${ths.searchCondition}`;
      }
      
      DataService.GlobalTaskListing(url).then((response) => {
        
        if (response.data.result.DATA.length > 0) {
          ths.GlobalTaskData = response.data.result.DATA;
          ths.TotalRecords = response.data.result.DATA[0].TOTAL_RECORDS;
          ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
          ths.CurrentPage = ths.PageNumber;
        } else {
          ths.GlobalTaskData = [];
        }
      })
    },
    commonDeleteData: function (event) {
      var vm = this;
      var val = "";
      vm.isLoading = true;
      $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
        if (val.length > 0)
          val += ',';
        val += $(this).val();
      });
      if (val != null) {
        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Project")), function () {
          var postJSON = {
            ids: val,
            moduleName: "PROJECT",
            subModuleCode: "PROJECT_DETAIL",
            refCode: 'TALYGEN_GLOBAL_TASK'
          };
          var objectPostString = JSON.stringify(postJSON)
          DataService.CommonCommonDelete(objectPostString).then(function (response) {
            vm.isLoading = false;
            if (response.status == 200) {
              vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('GlobalTask')]), "success", true, vm.$t("Alert"));
              vm.FetchData();
              vm.Key++;
            }
            else {
              vm.ShowAlert(vm.$t('DeletedError', [vm.$t('GlobalTask')]), "Success", true, vm.$t("Alert"));
            }
          });
        });
      }
      else {
        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
      }
      vm.isLoading = false;
    },
    AddGlobalTask: function (data) {
      this.GlobalTask = data;
      this.IsAddCloseGlobalTask = true;
    },
    Close()
    {
      this.IsAddCloseGlobalTask = false;
    }
  }
}
</script>